  function pie(d,o){clr(d);var w=d.clientWidth||400,h=d.clientHeight||300;var data=(o.series&&o.series[0]&&o.series[0].data)||[];var total=data.reduce((a,b)=>a+b.value,0)||1;var cx=w/2,cy=h/2,r=Math.min(w,h)/3,a=-Math.PI/2;var svg=S("svg",{width:w,height:h,viewBox:"0 0 "+w+" "+h});var colors=["#7e57c2","#ec407a","#26a69a","#fb8c00","#5c6bc0","#42a5f5","#66bb6a"];data.forEach((d2,i)=>{var ang=(d2.value/total)*Math.PI*2;var x1=cx+r*Math.cos(a),y1=cy+r*Math.sin(a);var x2=cx+r*Math.cos(a+ang),y2=cy+r*Math.sin(a+ang);var lar=ang>Math.PI?1:0;var path=["M",cx,cy,"L",x1,y1,"A",r,r,0,lar,1,x2,y2,"Z"].join(" ");svg.appendChild(S("path",{d:path,fill:colors[i%colors.length],opacity:.9}));var lx=cx+(r+18)*Math.cos(a+ang/2);var ly=cy+(r+18)*Math.sin(a+ang/2);var t=S("text",{x:lx,y:ly,"font-size":11,fill:"#345","text-anchor":"middle"});t.textContent=d2.name+":"+d2.value;svg.appendChild(t);a+=ang;});d.appendChild(svg);}
